import { useState, useEffect } from 'react';
import sensorService from '../services/sensorService';

export const useSensor = () => {
    const [status, setStatus] = useState({ connected: false });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [lastScan, setLastScan] = useState(null);

    useEffect(() => {
        checkStatus();
        
        // Poll status every 30 seconds
        const interval = setInterval(checkStatus, 30000);
        
        return () => clearInterval(interval);
    }, []);

    const checkStatus = async () => {
        try {
            const sensorStatus = await sensorService.getStatus();
            setStatus(sensorStatus);
        } catch (err) {
            console.error('Failed to check sensor status:', err);
        }
    };

    const testConnection = async () => {
        setLoading(true);
        setError(null);
        
        try {
            const result = await sensorService.testConnection();
            await checkStatus();
            return result;
        } catch (err) {
            setError(err.message);
            throw err;
        } finally {
            setLoading(false);
        }
    };

    const calibrate = async () => {
        setLoading(true);
        setError(null);
        
        try {
            const result = await sensorService.calibrate();
            return result;
        } catch (err) {
            setError(err.message);
            throw err;
        } finally {
            setLoading(false);
        }
    };

    const getLastScan = async () => {
        try {
            const scan = await sensorService.getLastScan();
            setLastScan(scan);
            return scan;
        } catch (err) {
            console.error('Failed to get last scan:', err);
        }
    };

    return {
        status,
        loading,
        error,
        lastScan,
        testConnection,
        calibrate,
        getLastScan,
        refreshStatus: checkStatus
    };
};
